/*
pushmove objects do not obey gravity and do not interact with trigger fields,
but block normal movement and push normal objects when they move.

doors/plats: SOLID_BSP + MOVETYPE_PUSH
bonus items: SOLID_TRIGGER touch + MOVETYPE_TOSS
corpses:     SOLID_NOT + MOVETYPE_TOSS
walking monsters: SOLID_SLIDEBOX + MOVETYPE_STEP
flying monsters:  SOLID_SLIDEBOX + MOVETYPE_FLY
*/

const MOVE_EPSILON = 0.01;

function svPhysicsToss(ent: Edict): void {
  // only called for MOVETYPE_TOSS entities
  if (ent.v.flags & FL_ONGROUND) return;
  svAddGravity(ent);
  svCheckVelocity(ent);
  svFlyMove(ent, host_frametime, null);
}
